func mustHex(s string) []byte {
	b, err := hex.DecodeString(strings.TrimPrefix(s, "0x"))
	if err != nil {
		panic(err)
	}
	return b
}

func TestML_KEM_512(t *testing.T) {
	k := WithFIPS203(cpapke.Level512)
	//k := &KEM{protocol: fips203.New(cpapke.Level512)}
	assert.Equal(t, "ML-KEM-Kyber-512", k.Scheme())

	z := mustHex("84CC9121AE56FBF39E67ADBD83AD2D3E3BB80843645206BDD9F2F629E3CC49B7")
	d := mustHex("2CB843A02EF02EE109305F39119FABF49AB90A57FFECB3A0E75E179450F52761")
	var seed [64]byte
	copy(seed[:], d)
	copy(seed[32:], z)

	pk, sk := k.GenerateKeyPair(seed[:])
	Ek := mustHex("")
	Dk := mustHex("")

	ek := k.UnPackPublicKey(Ek)
	dk := k.UnPackPrivateKey(Dk)

	assert.Equal(t, ek, pk)
	assert.Equal(t, dk, sk)

	Ekk := mustHex("")
	m := mustHex("6FF02E1DC7FD911BEEE0C692C8BD100C3E5C48964D31DF92994218E80664A6CA")
	ct1 := mustHex("")
	ss1 := mustHex("0BF323338D6F0A21D5514B673CD10B714CE6E36F35BCD1BF544196368EE51A13")

	ek1 := k.UnPackPublicKey(Ekk)
	ct, ss := k.Encapsulate(ek1, m)
	assert.Equal(t, ct1, ct)
	assert.Equal(t, ss1, ss)

	// Ciphertext hash decapsulated and shared-secret recovered.
	c := mustHex("")
	sk1 := mustHex("")
	k1 := mustHex("DF462AD68F1EC8972ED9B02D6DE0604BDEC75720E050497351E6EC933E71F882")

	sk2 := k.UnPackPrivateKey(sk1)
	ss2 := k.Decapsulate(sk2, c)
	assert.Equal(t, ss2[:], k1[:])

	// Ciphertext failed to decapsulated and arbitrary bits returned using KDF(z||H(ct)).
	c2 := mustHex("")
	sk3 := mustHex("")
	k2 := mustHex("A4A24E182FEA12FF128AB2D4AFE6569817513FFC547DB70636752C9C66C002B8")

	sk4 := k.UnPackPrivateKey(sk3)
	ss3 := k.Decapsulate(sk4, c2)
	assert.Equal(t, ss3[:], k2[:])
}

